import BpkButton from '../../bpk-component-button';
import { withButtonAlignment } from '../../bpk-component-icon/index';
import SmallLongArrowRightIcon from '../../bpk-component-icon/sm/long-arrow-right';
import { cssModules } from '../../bpk-react-utils';

import BpkSectionHeader, { SECTION_TYPES } from './BpkSectionHeader';

import type { Meta } from '@storybook/react';

import STYLES from './BpkSectionHeader.stories.module.scss';

const getClassName = cssModules(STYLES);

const AlignedSmallLongArrowRightIcon = withButtonAlignment(
  SmallLongArrowRightIcon,
);

const btnNode = <BpkButton>Action</BpkButton>;
const btnWithOnlyIconNode = (
  <BpkButton iconOnly>
    <AlignedSmallLongArrowRightIcon />
  </BpkButton>
);

const DefaultExample = () => <BpkSectionHeader title="Section title" />;

const WithDescriptionExample = () => (
  <BpkSectionHeader
    title="Section title"
    description="Description about this section"
  />
);

const WithButtonExample = () => (
  <BpkSectionHeader title="Section title" button={btnNode} />
);

const FullExample = () => (
  <BpkSectionHeader
    title="Section title"
    description="Description about this section"
    button={btnNode}
  />
);

const WithOnDarkExample = () => (
  <div className={getClassName('bpk-section-header-examples__on-dark')}>
    <BpkSectionHeader
      title="Section title"
      description="Description about this section"
      type={SECTION_TYPES.onDark}
    />
  </div>
);

const MobileExample = () => (
  <BpkSectionHeader
    title="Section title"
    description="Description about this section"
    button={btnWithOnlyIconNode}
  />
);

const MixedExample = () => (
  <div className={getClassName('bpk-section-header-examples__mixed')}>
    <DefaultExample />
    <WithDescriptionExample />
    <WithOnDarkExample />
    <FullExample />
    <MobileExample />
  </div>
);

const meta = {
  title: 'bpk-component-section-header',
  component: BpkSectionHeader,
} satisfies Meta;

export default meta;

export const Default = {
  render: () => <DefaultExample />,
};

export const WithDescription = {
  render: () => <WithDescriptionExample />,
};

export const WithButton = {
  render: () => <WithButtonExample />,
};

export const FullProps = {
  render: () => <FullExample />,
};

export const ForMobile = {
  render: () => <MobileExample />,
};

export const WithOnDark = {
  render: () => <WithOnDarkExample />,
};

export const VisualTest = {
  render: () => <MixedExample />,
};

export const VisualTestWithZoom = {
  render: () => <MixedExample />,
  args: {
    zoomEnabled: true,
  },
};
